function getFullHeight(el){const style=getComputedStyle(el);const marginTop=parseFloat(style.marginTop);const marginBottom=parseFloat(style.marginBottom);return el.offsetHeight+marginTop+marginBottom}
function setDetailsMaxHeight(details){const wasOpen=details.open;details.removeAttribute('open');details.setAttribute('open','');const offset=parseFloat(details.dataset.attributeMaxhoffset)||0;const contentHeight=[...details.children].filter(el=>el.tagName!=='SUMMARY').reduce((sum,el)=>sum+getFullHeight(el),0)-offset;details.style.setProperty('--details-max-height',`${contentHeight}px`);details.toggleAttribute('open',wasOpen)}
const allDetails=document.querySelectorAll('details');allDetails.forEach(setDetailsMaxHeight);let resizeTimer;window.addEventListener('resize',()=>{clearTimeout(resizeTimer);resizeTimer=setTimeout(()=>allDetails.forEach(setDetailsMaxHeight),150)});document.querySelector('#site-font-resize')?.addEventListener('click',()=>{requestAnimationFrame(()=>allDetails.forEach(setDetailsMaxHeight))});